const res = $input.first().json;
const rows = res.values || [];
const pending = [];
for (let i = 0; i < rows.length; i++) {
  if ((rows[i][1]||'').toString().trim() === 'Approved' && (rows[i][5]||'').toString().trim()) pending.push({ idx: i, row: rows[i] });
}
if (!pending.length) throw new Error('No Approved rows with a Quote filled in. Check column B = Approved and column F (Quote) is non-empty in Aperture Topics sheet.');

// Filter out rows where quote is clearly not a real quote (too short or looks like metadata)
const validPending = pending.filter(p => (p.row[5]||'').trim().split(/\s+/).length >= 5);
if (!validPending.length) throw new Error('All Approved rows have quotes that are too short (< 5 words) — check column F in the Aperture Topics sheet for real quote text.');
const usePending = validPending;
const found = usePending[Math.floor(Math.random() * usePending.length)];
const sheetRow = found.idx + 2;
return [{ json: {
