  status:      (found.row[1]||'Approved').trim(),
  philosopher: (found.row[2]||'').trim(),
  era:         (found.row[3]||'').trim(),
  theme:       (found.row[4]||'').trim(),
  quote:       (found.row[5]||'').trim(),
  hashtags:    (found.row[6]||'#philosophy #psychology #aperture').trim(),
  sheet_row:   sheetRow,
  source:      'google_sheet'
}}];

