const https = require('https');
const data = $input.first().json;
const { philosopher, era, theme, quote } = data;

if (!quote) throw new Error('Missing quote — this node no longer generates or verifies quotes, it only writes the image prompt and caption for a quote already provided by the sheet.');

const ANTHROPIC_KEY = $env.ANTHROPIC_API_KEY;
if (!ANTHROPIC_KEY) throw new Error('ANTHROPIC_API_KEY not set.');

const prompt = `You are the visual + copy director for Aperture, a philosophy / psychology / wisdom Instagram & YouTube Shorts channel by Underknown. Aperture posts single-image "quote card" videos: one real quote, painted as a cinematic illustration with the quote text overlaid, plus a written caption for the post.

CHANNEL DESCRIPTION (verbatim brief): "Your window to the Bigger Picture. This channel is about philosophy, psychology, and society, where we explore the deep questions of existence and where humanity is headed. Big ideas about consciousness, meaning, and what it means to be alive."

The quote below is ALREADY CHOSEN AND VERIFIED — it comes directly from a curated, human-checked sheet. Do NOT alter, shorten, paraphrase, or "improve" it in any way. Your job is only to (1) design the painting that will sit behind it, and (2) write a caption for the post.

PHILOSOPHER / SOURCE: ${philosopher}
ERA: ${era || 'historical'}
THEME / CATEGORY: ${theme || 'Philosophy'}
QUOTE (verbatim, already verified — use exactly as given, do not touch it): "${quote}"

=====================================================
IMAGE PROMPT RULES — CRITICAL
=====================================================
Aperture's visual house style is a SEMI-REALISTIC CINEMATIC OIL-PAINTING illustration — never a photo, never a 3D render, never flat cartoon/anime, never comic-book style. Think museum-quality digital matte painting / classical oil portraiture: visible brushwork, rich color grading, dramatic natural lighting.

STEP 1 — GROUND THE SETTING IN THIS SPECIFIC PERSON'S ACTUAL ORIGIN, NEVER A DEFAULT.
Identify where and when this exact person/tradition actually comes from, and build the entire scene from that — do NOT default to Greco-Roman ruins/columns for everyone. Examples of the range you must draw from based on who it actually is: Chinese/Confucian/Taoist figures -> Chinese architecture, robes, calligraphy, bamboo, mountains, pagodas. Persian/Sufi figures (Rumi, Hafez) -> Persian gardens, tiled mosques, whirling fabric, desert caravans. Japanese sources -> torii gates, rice fields, katana, cherry blossoms, minimalist wood interiors. Indian/Hindu/Buddhist sages -> ashrams, ghats, temple carvings, saffron and white cloth, Himalayan paths. African wisdom -> savanna, tribal dress, baobab trees, village elders. Arabic/Islamic scholars -> Andalusian or Levantine courtyards, geometric tilework, desert. European Enlightenment/existentialist thinkers -> European stone architecture, libraries, rain-lit streets, period dress of their actual century. Modern/living voices or businesspeople -> a real plausible contemporary setting appropriate to their actual life and work (a study, a city street, an office, a stage, nature). Ancient Greek/Roman figures are the ONLY ones who should get togas and marble columns — reserve that look for them specifically, not as a generic "ancient wisdom" default. Scientists get real labs/instruments/observatories relevant to their actual field and century. Founding documents / proverbs / traditions -> depict a representative figure or symbolic scene from that culture, not a generic parchment.

STEP 2 — LET THE SCENE QUIETLY ENCODE THE QUOTE'S MEANING, LIKE A CLASSICAL ALLEGORICAL PAINTING.
Don't just place a generic figure in a pretty backdrop — choose one concrete action, object, or composition detail that works as a visual metaphor for what THIS quote is actually saying, the way a Renaissance painting hides meaning in small symbolic details (a mirror, a candle burning down, an open door, a bird in flight, a hand almost touching something). Make the viewer feel the idea before they finish reading the words.

Every image_prompt MUST also:
- Depict ONE real human figure. Show them from behind, in profile, at mid-distance, or partially silhouetted — NOT a tight frontal close-up of a face, and never looking directly into the camera.
- Use dramatic, natural directional light — golden hour, dusk, moonlight, firelight, or candlelight — with strong warm/cool contrast and deep, moody shadow falloff.
- Be composed for a SQUARE (1:1) crop with the main subject centered or on a strong vertical third.
- End with: "...semi-realistic cinematic oil painting, painterly digital matte painting, visible brushwork, rich color grading, highly detailed, no text no watermark no signature"

NEVER include in the prompt: on-screen text, captions, logos, watermarks, a signature, cartoon style, anime style, 3D render, CGI, photograph, photorealistic (this is a PAINTING, not a photo), a person looking directly into the camera.

=====================================================
CAPTION RULES — CRITICAL
=====================================================
Write a 3-4 paragraph caption/story for the social post (Instagram/YouTube description) that accompanies the video. It should:
- Open with something that hooks a scrolling reader in the first line (a question, a striking observation, or context for the quote).
- Give real context: who this person/tradition was, and why this specific quote matters or what it actually means in practice.
- Connect it to a modern, relatable struggle or moment the reader might recognize in their own life.
- Close with a short reflective line or gentle question that invites the reader to sit with the idea — NOT a generic CTA like "follow for more" (that's handled separately).
- Written in a warm, direct, second-person-friendly essayist voice — the same voice as the channel's brief. No hashtags inside the caption body itself.

=====================================================
OUTPUT — RETURN ONLY RAW JSON, NO MARKDOWN, NO FENCES
=====================================================
{
  "attribution": "exact text to display after the dash on the image, e.g. Marcus Aurelius",
  "image_prompt": "80-110 word Seedream prompt following all rules above",
  "caption": "3-4 paragraph caption as plain text, paragraphs separated by \\n\\n",
  "title": "SHORT PUNCHY TITLE CASE",
  "hashtags": "#philosophy #aperture ...(6-10 relevant tags)"
}`;

const buf = Buffer.from(JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 4000,
  messages: [{ role: 'user', content: prompt }]
}));

const response = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.anthropic.com',
    path: '/v1/messages',
    method: 'POST',
    headers: {
      'x-api-key': ANTHROPIC_KEY,
      'anthropic-version': '2023-06-01',
      'Content-Type': 'application/json',
      'Content-Length': buf.length
    }
  }, (res) => {
    const chunks = [];
    res.on('data', c => chunks.push(c));
    res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { reject(new Error('Bad JSON from Anthropic: ' + Buffer.concat(chunks).toString().slice(0,300))); } });
  });
  req.on('error', reject);
  req.write(buf);
  req.end();
});

if (!response.content || !response.content[0] || !response.content[0].text)
  throw new Error('Claude response empty — check ANTHROPIC_API_KEY. Error: ' + JSON.stringify(response).slice(0,200));

let raw = response.content[0].text.trim();
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

let parsed;
try { parsed = JSON.parse(raw); }
catch(e) {
  const s = raw.indexOf('{'), end = raw.lastIndexOf('}');
  if (s === -1 || end === -1) throw new Error('Claude did not return valid JSON: ' + raw.slice(0, 300));
  parsed = JSON.parse(raw.slice(s, end + 1));
}

if (!parsed.image_prompt || !parsed.caption)
  throw new Error('Claude response missing required fields (image_prompt/caption): ' + JSON.stringify(parsed).slice(0,300));

const NEGATIVE_PROMPT = 'text, watermark, signature, logo, caption, subtitle, cartoon, anime, 3D render, CGI, photograph, photorealistic photo, blurry, low quality, extra limbs, distorted hands, frontal close-up face, looking directly at camera';

console.log('Generated for ' + philosopher + ' | title: ' + parsed.title);

return [{ json: {
  ...data,
  attribution:     parsed.attribution || philosopher,
  image_prompt:    parsed.image_prompt,
  negative_prompt: NEGATIVE_PROMPT,
  caption:         parsed.caption,
  title:           parsed.title    || philosopher,
  hashtags:        parsed.hashtags || data.hashtags
}}];

const { execSync } = require('child_process');
const data   = $input.first().json;
const jobId  = data.job_id;
const VIDEO_DUR = 15;

const bgmDir = '/ffmpeg/config/bgm_aperture';
let ls = execSync('docker exec qpc_ffmpeg_runner bash -c "ls ' + bgmDir + '/*.mp3 2>/dev/null | sort"', { encoding: 'utf-8', timeout: 10000 }).trim();
if (!ls) {
  console.warn('No BGM in ' + bgmDir + ' — falling back to shared /ffmpeg/config/bgm');
  ls = execSync('docker exec qpc_ffmpeg_runner bash -c "ls /ffmpeg/config/bgm/*.mp3 2>/dev/null | sort"', { encoding: 'utf-8', timeout: 10000 }).trim();
}
if (!ls) throw new Error('No BGM tracks found in /ffmpeg/config/bgm_aperture/ or /ffmpeg/config/bgm/ — add ambient/cinematic .mp3 files.');

const tracks = ls.split('\n').map(p => p.trim()).filter(Boolean);
const seed   = parseInt(String(jobId).replace(/\D/g,'').slice(-6)||'1', 10);
const picked = tracks[seed % tracks.length];

const bgmN8n  = '/data/ffmpeg/input/' + jobId + '_bgm.mp3';
const bgmCont = '/ffmpeg/input/'      + jobId + '_bgm.mp3';

const trim = 'docker exec qpc_ffmpeg_runner ffmpeg -y ' +
  '-stream_loop -1 -i "' + picked + '" ' +
  '-t ' + VIDEO_DUR + ' ' +
  '-af "afade=t=in:st=0:d=1.5,afade=t=out:st=' + (VIDEO_DUR-1.5).toFixed(3) + ':d=1.5,volume=0.55" ' +
  '-acodec libmp3lame -ab 128k "' + bgmCont + '" 2>&1 && echo TRIM_OK';

const res = execSync(trim, { encoding: 'utf-8', timeout: 30000 });
if (!res.includes('TRIM_OK')) throw new Error('BGM trim failed: ' + res.slice(-300));

console.log('BGM: ' + picked.split('/').pop() + ' | ' + VIDEO_DUR + 's');

return [{ json: { ...data, bgm_path: bgmN8n } }];
